import { useState } from "react";
import { uploadPDF } from "../services/api";

export default function UploadPDF() {
  const [file, setFile] = useState(null);
  const [status, setStatus] = useState("");

  const upload = async () => {
    if (!file) {
      alert("Select PDF first");
      return;
    }

    try {
      setStatus("Uploading and processing PDF... please wait");

      const formData = new FormData();
      formData.append("file", file);

      const data = await uploadPDF(formData);

      setStatus(data.status || data.message || "PDF uploaded successfully");
    } catch (error) {
      console.error("Upload error:", error);

      if (error.code === "ECONNABORTED") {
        setStatus("Upload timed out. PDF processing is taking too long.");
      } else if (error.response) {
        setStatus(`Upload failed: ${JSON.stringify(error.response.data)}`);
      } else {
        setStatus("Upload failed. Check FastAPI server.");
      }
    }
  };

  return (
    <div className="upload-box">
      <input
        type="file"
        accept="application/pdf"
        onChange={(e) => setFile(e.target.files[0])}
      />

      <button className="upload-btn" onClick={upload}>
        Upload PDF
      </button>

      {status && <p>{status}</p>}
    </div>
  );
}
